/**
 * model-viewer fallback runtime.
 *
 * Used when WebXR immersive-ar isn't available — covers:
 *   - iOS Safari (Quick Look handoff via the `ios-src` USDZ)
 *   - Android Chrome (Scene Viewer handoff via the `src` GLB)
 *   - Anything else with model-viewer support → 3D preview, AR-when-tapped
 *
 * The actual AR session runs in the OS app (Quick Look / Scene Viewer),
 * so we don't see gesture events or placement events from inside the
 * page. We emit a synthesised `item.placed` event when the user opens
 * AR mode (model-viewer fires `ar-status="session-started"`), and an
 * `item.removed` event when AR exits.
 *
 * model-viewer is loaded lazily from a CDN so the initial viewer
 * bundle stays small.
 */

import { RuntimeEventBus } from './event-bus';
import type { ArRuntime, RuntimeEventListener, RuntimePath } from './types';
import type { Item } from '@nova-ar/types';

const MODEL_VIEWER_TAG = 'model-viewer';
const MODEL_VIEWER_CDN =
  'https://ajax.googleapis.com/ajax/libs/model-viewer/4.0.0/model-viewer.min.js';

let modelViewerLoading: Promise<void> | null = null;

async function ensureModelViewerLoaded(): Promise<void> {
  if (typeof customElements !== 'undefined' && customElements.get(MODEL_VIEWER_TAG)) return;
  if (modelViewerLoading) return modelViewerLoading;
  modelViewerLoading = new Promise<void>((resolve, reject) => {
    const script = document.createElement('script');
    script.type = 'module';
    script.src = MODEL_VIEWER_CDN;
    script.onload = () => resolve();
    script.onerror = () =>
      reject(new Error(`failed to load model-viewer from ${MODEL_VIEWER_CDN}`));
    document.head.append(script);
  });
  return modelViewerLoading;
}

export interface ModelViewerRuntimeOptions {
  /** Inject a stub element factory in tests instead of touching the DOM. */
  readonly createElement?: (tag: string) => HTMLElement;
  /** Override model-viewer loader (tests). */
  readonly ensureLoaded?: () => Promise<void>;
}

export function createModelViewerRuntime(opts: ModelViewerRuntimeOptions = {}): ArRuntime {
  const bus = new RuntimeEventBus();
  const factory = opts.createElement ?? ((tag: string) => document.createElement(tag));
  const ensureLoaded = opts.ensureLoaded ?? ensureModelViewerLoaded;

  let activeElement: HTMLElement | null = null;
  let activePlacementId: string | null = null;
  let arStatusListener: ((e: Event) => void) | null = null;

  return {
    runtimePath: 'model-viewer' as RuntimePath,

    async launch(item: Item, container: HTMLElement): Promise<void> {
      await ensureLoaded();

      const el = factory(MODEL_VIEWER_TAG);
      // Assets
      el.setAttribute('src', item.assets.glb);
      if (item.assets.usdz) el.setAttribute('ios-src', item.assets.usdz);
      const poster = item.assets.thumbnails[0];
      if (poster) el.setAttribute('poster', poster);
      // AR config. Order: webxr → scene-viewer → quick-look (model-viewer's
      // own default). model-viewer's in-browser WebXR is robust and is the
      // ONLY mode that works on devices whose Scene Viewer is broken
      // (field-tested: an Adreno phone with a non-functional Scene Viewer
      // placed fine via WebXR). model-viewer picks the first SUPPORTED mode
      // per device, so iOS still gets Quick Look and Scene-Viewer-only
      // devices still get Scene Viewer.
      el.setAttribute('ar', '');
      el.setAttribute('ar-modes', 'webxr scene-viewer quick-look');
      el.setAttribute('ar-scale', 'fixed');
      el.setAttribute('ar-placement', item.placement === 'wall-ceiling' ? 'wall' : 'floor');
      el.setAttribute('camera-controls', '');
      el.setAttribute('touch-action', 'pan-y');
      el.setAttribute('shadow-intensity', '1');
      el.setAttribute('shadow-softness', '0.6');
      el.setAttribute('environment-image', 'neutral');
      // Lively preview — the product spins on its own (the "wow" the brand
      // wants) and a soft hand prompt invites the shopper to grab + rotate
      // it before they place it in their room.
      el.setAttribute('auto-rotate', '');
      // Resume the idle spin 3s AFTER the shopper stops dragging, so their
      // drag-to-rotate isn't fought by the auto-spin — the rotation is
      // fully interactive (drag the product with a finger), the spin is
      // just an idle attractor.
      el.setAttribute('auto-rotate-delay', '3000');
      el.setAttribute('rotation-per-second', '24deg');
      el.setAttribute('interaction-prompt', 'auto');
      el.setAttribute('interaction-prompt-style', 'wiggle');
      el.setAttribute('camera-orbit', '-20deg 80deg 110%');
      el.setAttribute('exposure', '1.05');
      // ar-scale defaults to 'fixed' (real-world dimensions). The host
      // can opt the item into pinch-to-resize via the per-item
      // `swappableMaterials` / `playableAnimations` schema additions in
      // S21–S22 by setting `el.setAttribute('ar-scale', 'auto')` post-
      // mount. The default protects measured furniture from being
      // resized into miniature.
      // Layout
      el.style.width = '100%';
      el.style.height = '100%';
      el.style.display = 'block';
      // Load the model eagerly + show model-viewer's own progress bar so
      // the user sees the 3D preview load instead of a blank panel.
      el.setAttribute('reveal', 'auto');
      el.setAttribute('loading', 'eager');

      // Surface a failed model load so a bad GLB fetch shows up as an
      // error event rather than a silent black panel. (Success is already
      // signalled by the session.start emitted at the end of launch.)
      el.addEventListener('error', (event: Event) => {
        const detail = (event as CustomEvent<{ type?: string }>).detail;
        bus.emit({
          kind: 'error',
          code: 'model-viewer.load-failed',
          message: `model failed to load (${detail?.type ?? 'unknown'}): ${item.assets.glb}`,
        });
      });

      arStatusListener = (event: Event) => {
        const detail = (event as CustomEvent<{ status: string }>).detail;
        const status = detail?.status ?? '';
        if (status === 'session-started') {
          activePlacementId = `p_${Date.now()}`;
          bus.emit({
            kind: 'item.placed',
            placementId: activePlacementId,
            itemId: item.id,
            placement: item.placement,
            pose: { x: 0, y: 0, z: 0, qx: 0, qy: 0, qz: 0, qw: 1 },
          });
        } else if (status === 'not-presenting' && activePlacementId) {
          bus.emit({ kind: 'item.removed', placementId: activePlacementId });
          activePlacementId = null;
        } else if (status === 'failed') {
          bus.emit({
            kind: 'error',
            code: 'model-viewer.ar-failed',
            message: 'AR session failed to start',
          });
        }
      };
      el.addEventListener('ar-status', arStatusListener);

      container.replaceChildren(el);
      activeElement = el;
      bus.emit({ kind: 'session.start', runtimePath: 'model-viewer' });
    },

    on(listener: RuntimeEventListener): () => void {
      return bus.on(listener);
    },

    async end(): Promise<void> {
      if (activeElement && arStatusListener) {
        activeElement.removeEventListener('ar-status', arStatusListener);
      }
      activeElement?.remove();
      activeElement = null;
      arStatusListener = null;
      bus.emit({ kind: 'session.end' });
      bus.clear();
    },
  };
}
